mapper.select:
SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT r.*, NVL(uc.USER_COUNT, 0) AS USER_COUNT FROM FWK_ROLE r LEFT JOIN ( SELECT ROLE_ID, COUNT(*) AS USER_COUNT FROM FWK_USER GROUP BY ROLE_ID ) uc ON r.ROLE_ID = uc.ROLE_ID
ORDER BY r.ROLE_ID DESC ORDER BY r.ROLE_NAME ASC ORDER BY r.ROLE_NAME DESC ORDER BY r.USE_YN ASC ORDER BY r.USE_YN DESC ORDER BY r.ROLE_DESC ASC ORDER BY r.ROLE_DESC DESC ORDER BY r.RANKING ASC ORDER BY r.RANKING DESC ORDER BY r.ROLE_ID ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
